package org.apache.commons.math.complex;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources/requirement.feature",
    glue = "org.apache.commons.math.complex.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.apache.commons.math.complex.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.apache.commons.math.complex.Complex;
import org.apache.commons.math.complex.ComplexUtils;
import static org.junit.Assert.*;

public class StepDefs {

    private Complex z;
    private Complex result;

    @Given("a complex number z with real part Infinity and imaginary part 1.0")
    public void given_complex_number_with_infinity_real_part() {
        z = new Complex(Double.POSITIVE_INFINITY, 1.0);
    }

    @Given("a complex number z with real part -Infinity and imaginary part 1.0")
    public void given_complex_number_with_negative_infinity_real_part() {
        z = new Complex(Double.NEGATIVE_INFINITY, 1.0);
    }

    @Given("a complex number z with real part 1.0E10 and imaginary part 3.0")
    public void given_complex_number_with_large_positive_real_part() {
        z = new Complex(1.0E10, 3.0);
    }

    @Given("a complex number z with real part -1.0E10 and imaginary part 3.0")
    public void given_complex_number_with_large_negative_real_part() {
        z = new Complex(-1.0E10, 3.0);
    }

    @When("I compute the hyperbolic tangent of z")
    public void when_compute_hyperbolic_tangent() {
        try {
            result = z.tanh();
        } catch (Exception e) {
            // Capture any exception if needed for error testing
            result = null;
        }
    }

    @Then("the result should be the complex number (1.0, 0.0)")
    public void then_result_should_be_positive_one() {
        assertNotNull("Result should not be null", result);
        assertEquals("Real part should be 1.0", 1.0, result.getReal(), 1e-10);
        assertEquals("Imaginary part should be 0.0", 0.0, result.getImaginary(), 1e-10);
    }

    @Then("the result should be the complex number (-1.0, 0.0)")
    public void then_result_should_be_negative_one() {
        assertNotNull("Result should not be null", result);
        assertEquals("Real part should be -1.0", -1.0, result.getReal(), 1e-10);
        assertEquals("Imaginary part should be 0.0", 0.0, result.getImaginary(), 1e-10);
    }
}

